graphql.query:
query GetUsers($dept: String, $page: Int, $limit: Int) {
  users(department: $dept, page: $page, limit: $limit) {
    total
    page
    totalPages
    data {
      id
      name
      email
      role
      department
      isActive
    }
  }
}

mutation Login($email: String!, $password: String!) {
  login(email: $email, password: $password) {
    accessToken
    refreshToken
    user { id name role }
  }
}

